# --- Logging Configuration ---
logger = logging.getLogger()
logger.setLevel(getattr(logging, os.environ.get('LOG_LEVEL', 'INFO')))

# Sanitize log output to prevent log injection
class LogSanitizer(logging.Filter):
    """Prevents log injection attacks by sanitizing log messages."""
    
    DANGEROUS_PATTERNS = re.compile(r'[\r\n\x00-\x1f\x7f-\x9f]')
    
    def filter(self, record):
        if isinstance(record.msg, str):
            record.msg = self.DANGEROUS_PATTERNS.sub('', record.msg)
        return True

logger.addFilter(LogSanitizer())


# --- Configuration ---
ENVIRONMENT = os.environ.get('ENVIRONMENT', 'dev')
SERVICE_PREFIX = os.environ.get('SERVICE_PREFIX', 'myapp')
ALLOWED_ENVIRONMENTS = {'dev', 'staging', 'prod'}
MAX_INPUT_SIZE = 1_000_000  # 1MB max input size
ALLOWED_S3_BUCKETS_PREFIX = f"{SERVICE_PREFIX}-{ENVIRONMENT}-"
ALLOWED_DYNAMODB_TABLE_PREFIX = f"{SERVICE_PREFIX}-{ENVIRONMENT}-"
ALLOWED_SNS_TOPIC_PREFIX = f"{SERVICE_PREFIX}-{ENVIRONMENT}-"
ALLOWED_SQS_QUEUE_PREFIX = f"{SERVICE_PREFIX}-{ENVIRONMENT}-"


# --- Input Validation ---
class InputValidationError(Exception):
    """Raised when input validation fails."""
    pass


class SecurityViolationError(Exception):
    """Raised when a security policy is violated."""
    pass


def validate_environment():
    """Validate that the environment is properly configured."""
    if ENVIRONMENT not in ALLOWED_ENVIRONMENTS:
        raise SecurityViolationError(
            f"Invalid environment: {ENVIRONMENT}. "
            f"Allowed: {ALLOWED_ENVIRONMENTS}"
        )


def sanitize_string(value: str, max_length: int = 1024, field_name: str = "field") -> str:
    """Sanitize a string input to prevent injection attacks."""
    if not isinstance(value, str):
        raise InputValidationError(f"{field_name} must be a string")
    if len(value) > max_length:
        raise InputValidationError(
            f"{field_name} exceeds maximum length of {max_length}"
        )
    # Remove null bytes and control characters
    sanitized = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', '', value)
    return sanitized


def validate_resource_name(resource_name: str, allowed_prefix: str, resource_type: str) -> str:
    """
    Validate that a resource name matches the expected prefix.
    Prevents accessing resources outside the service boundary.
    """
    sanitized = sanitize_string(resource_name, max_length=256, field_name=resource_type)
    
    # Prevent path traversal in resource names
    if '..' in sanitized or '//' in sanitized:
        raise SecurityViolationError(
            f"Path traversal detected in {resource_type}: {sanitized}"
        )
    
    if not sanitized.startswith(allowed_prefix):
        raise SecurityViolationError(
            f"{resource_type} '{sanitized}' does not match allowed prefix '{allowed_prefix}'. "
            f"Cross-service access is not permitted."
        )
    
    return sanitized


def validate_event_size(event: dict) -> None:
    """Validate that the event payload is within acceptable size limits."""
    event_size = len(json.dumps(event))
    if event_size > MAX_INPUT_SIZE:
        raise InputValidationError(
            f"Event payload size ({event_size} bytes) exceeds maximum ({MAX_INPUT_SIZE} bytes)"
        )


# --- Secure Service Clients ---
class SecureServiceClients:
    """
    Provides pre-configured, security-scoped AWS service clients.
    Enforces resource naming conventions and access boundaries.
    """
    
    _instances = {}
    
    def __init__(self):
        self._region = os.environ.get('AWS_REGION', 'us-east-1')
        self._account_id = None
        self._s3_client = None
        self._dynamodb_resource = None
        self._sns_client = None
        self._sqs_client = None
    
    @classmethod
    def get_instance(cls) -> 'SecureServiceClients':
        """Singleton pattern for client reuse across invocations."""
        if 'default' not in cls._instances:
            cls._instances['default'] = cls()
        return cls._instances['default']
    
    @property
    def account_id(self) -> str:
        if self._account_id is None:
            sts = boto3.client('sts')
            self._account_id = sts.get_caller_identity()['Account']
        return self._account_id
    
    @property
    def s3(self):
        if self._s3_client is None:
            self._s3_client = boto3.client('s3', region_name=self._region)
        return self._s3_client
    
    @property
    def dynamodb(self):
        if self._dynamodb_resource is None:
            self._dynamodb_resource = boto3.resource('dynamodb', region_name=self._region)
        return self._dynamodb_resource
    
    @property
    def sns(self):
        if self._sns_client is None:
            self._sns_client = boto3.client('sns', region_name=self._region)
        return self._sns_client
    
    @property
    def sqs(self):
        if self._sqs_client is None:
            self._sqs_client = boto3.client('sqs', region_name=self._region)
        return self._sqs_client
    
    # --- S3 Operations (scoped) ---
    def s3_get_object(self, bucket: str, key: str) -> dict:
        """Get an object from S3 with bucket name validation."""
        validated_bucket = validate_resource_name(
            bucket, ALLOWED_S3_BUCKETS_PREFIX, "S3 bucket"
        )
        validated_key = sanitize_string(key, max_length=1024, field_name="S3 key")
        
        if '..' in validated_key:
            raise SecurityViolationError(f"Path traversal in S3 key: {validated_key}")
        
        logger.info(f"S3 GetObject: bucket={validated_bucket}, key={validated_key}")
        return self.s3.get_object(Bucket=validated_bucket, Key=validated_key)
    
    def s3_put_object(self, bucket: str, key: str, body: bytes,
                      server_side_encryption: str = 'AES256',
                      content_type: str = 'application/octet-stream') -> dict:
        """Put an object to S3 with encryption enforced."""
        validated_bucket = validate_resource_name(
            bucket, ALLOWED_S3_BUCKETS_PREFIX, "S3 bucket"
        )
        validated_key = sanitize_string(key, max_length=1024, field_name="S3 key")
        
        if '..' in validated_key:
            raise SecurityViolationError(f"Path traversal in S3 key: {validated_key}")
        
        logger.info(f"S3 PutObject: bucket={validated_bucket}, key={validated_key}, "
                     f"size={len(body)}, encryption={server_side_encryption}")
        
        return self.s3.put_object(
            Bucket=validated_bucket,
            Key=validated_key,
            Body=body,
            ServerSideEncryption=server_side_encryption,
            ContentType=content_type
        )
    
    def s3_delete_object(self, bucket: str, key: str) -> dict:
        """Delete an object from S3 with validation."""
        validated_bucket = validate_resource_name(
            bucket, ALLOWED_S3_BUCKETS_PREFIX, "S3 bucket"
        )
        validated_key = sanitize_string(key, max_length=1024, field_name="S3 key")
        
        logger.info(f"S3 DeleteObject: bucket={validated_bucket}, key={validated_key}")
        return self.s3.delete_object(Bucket=validated_bucket, Key=validated_key)
    
    # --- DynamoDB Operations (scoped) ---
    def dynamodb_get_table(self, table_name: str):
        """Get a DynamoDB table reference with name validation."""
        validated_table = validate_resource_name(
            table_name, ALLOWED_DYNAMODB_TABLE_PREFIX, "DynamoDB table"
        )
        return self.dynamodb.Table(validated_table)
    
    def dynamodb_get_item(self, table_name: str, key: dict) -> Optional[dict]:
        """Get an item from DynamoDB."""
        table = self.dynamodb_get_table(table_name)
        logger.info(f"DynamoDB GetItem: table={table_name}")
        response = table.get_item(Key=key)
        return response.get('Item')
    
    def dynamodb_put_item(self, table_name: str, item: dict) -> dict:
        """Put an item into DynamoDB."""
        table = self.dynamodb_get_table(table_name)
        logger.info(f"DynamoDB PutItem: table={table_name}")
        return table.put_item(Item=item)
    
    def dynamodb_update_item(self, table_name: str, key: dict,
                              update_expression: str,
                              expression_values: dict,
                              expression_names: Optional[dict] = None) -> dict:
        """Update an item in DynamoDB using parameterized expressions."""
        table = self.dynamodb_get_table(table_name)
        
        # Validate update expression doesn't contain raw values (must use placeholders)
        if any(char in update_expression for char in ['"', "'"]):
            raise SecurityViolationError(
                "Update expressions must use expression attribute values, not literal values"
            )
        
        logger.info(f"DynamoDB UpdateItem: table={table_name}")
        
        kwargs = {
            'Key': key,
            'UpdateExpression': update_expression,
            'ExpressionAttributeValues': expression_values,
            'ReturnValues': 'ALL_NEW'
        }
        if expression_names:
            kwargs['ExpressionAttributeNames'] = expression_names
        
        return table.update_item(**kwargs)
    
    def dynamodb_query(self, table_name: str, key_condition_expression,
                       expression_values: dict,
                       index_name: Optional[str] = None,
                       limit: int = 100) -> list:
        """Query DynamoDB with result limiting."""
        table = self.dynamodb_get_table(table_name)
        
        # Enforce reasonable query limits
        safe_limit = min(limit, 1000)
        
        logger.info(f"DynamoDB Query: table={table_name}, limit={safe_limit}")
        
        kwargs = {
            'KeyConditionExpression': key_condition_expression,
            'ExpressionAttributeValues': expression_values,
            'Limit': safe_limit
        }
        if index_name:
            kwargs['IndexName'] = sanitize_string(index_name, max_length=256, field_name="index")
        
        response = table.query(**kwargs)
        return response.get('Items', [])
    
    # --- SNS Operations (scoped) ---
    def sns_publish(self, topic_name: str, message: str,
                    subject: Optional[str] = None,
                    message_attributes: Optional[dict] = None) -> dict:
        """Publish a message to an SNS topic with validation."""
        validated_topic = validate_resource_name(
            topic_name, ALLOWED_SNS_TOPIC_PREFIX, "SNS topic"
        )
        
        topic_arn = (
            f"arn:aws:sns:{self._region}:{self.account_id}:{validated_topic}"
        )
        
        sanitized_message = sanitize_string(message, max_length=262144, field_name="SNS message")
        
        logger.info(f"SNS Publish: topic={validated_topic}, message_size={len(sanitized_message)}")
        
        kwargs = {
            'TopicArn': topic_arn,
            'Message': sanitized_message
        }
        if subject:
            kwargs['Subject'] = sanitize_string(subject, max_length=100, field_name="SNS subject")
        if message_attributes:
            kwargs['MessageAttributes'] = message_attributes
        
        return self.sns.publish(**kwargs)
    
    # --- SQS Operations (scoped) ---
    def sqs_send_message(self, queue_name: str, message_body: str,
                          delay_seconds: int = 0,
                          message_attributes: Optional[dict] = None) -> dict:
        """Send a message to an SQS queue with validation."""
        validated_queue = validate_resource_name(
            queue_name, ALLOWED_SQS_QUEUE_PREFIX, "SQS queue"
        )
        
        queue_url = (
            f"https://sqs.{self._region}.amazonaws.com/{self.account_id}/{validated_queue}"
        )
        
        sanitized_body = sanitize_string(
            message_body, max_length=262144, field_name="SQS message body"
        )
        
        safe_delay = max(0, min(delay_seconds, 900))
        
        logger.info(f"SQS SendMessage: queue={validated_queue}, size={len(sanitized_body)}")
        
        kwargs = {
            'QueueUrl': queue_url,
            'MessageBody': sanitized_body,
            'DelaySeconds': safe_delay
        }
        if message_attributes:
            kwargs['MessageAttributes'] = message_attributes
        
        return self.sqs.send_message(**kwargs)
    
    def sqs_receive_messages(self, queue_name: str,
                              max_messages: int = 10,
                              wait_time_seconds: int = 5) -> list:
        """Receive messages from an SQS queue."""
        validated_queue = validate_resource_name(
            queue_name, ALLOWED_SQS_QUEUE_PREFIX, "SQS queue"
        )
        
        queue_url = (
            f"https://sqs.{self._region}.amazonaws.com/{self.account_id}/{validated_queue}"
        )
        
        safe_max = max(1, min(max_messages, 10))
        safe_wait = max(0, min(wait_time_seconds, 20))
        
        logger.info(f"SQS ReceiveMessage: queue={validated_queue}, max={safe_max}")
        
        response = self.sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=safe_max,
            WaitTimeSeconds=safe_wait,
            AttributeNames=['All'],
            MessageAttributeNames=['All']
        )
        
        return response.get('Messages', [])
    
    def sqs_delete_message(self, queue_name: str, receipt_handle: str) -> dict:
        """Delete a message from an SQS queue."""
        validated_queue = validate_resource_name(
            queue_name, ALLOWED_SQS_QUEUE_PREFIX, "SQS queue"
        )
        
        queue_url = (
            f"https://sqs.{self._region}.amazonaws.com/{self.account_id}/{validated_queue}"
        )
        
        logger.info(f"SQS DeleteMessage: queue={validated_queue}")
        
        return self.sqs.delete_message(
            QueueUrl=queue_url,
            ReceiptHandle=receipt_handle
        )


# --- Security Decorators ---
def secure_handler(require_fields: Optional[list] = None,
                   max_execution_time_warning: int = 25):
    """
    Decorator that wraps Lambda handlers with security controls:
    - Input validation and size checking
    - Environment validation
    - Error handling that doesn't leak internals
    - Execution time monitoring
    - Request ID tracking
    """
    def decorator(func):
        @wraps(func)
        def wrapper(event, context):
            request_id = getattr(context, 'aws_request_id', 'unknown')
            function_name = getattr(context, 'function_name', 'unknown')
            start_time = time.time()
            
            try:
                # Validate environment
                validate_environment()
                
                # Validate event size
                validate_event_size(event)
                
                # Validate required fields
                if require_fields:
                    missing = [f for f in require_fields if f not in event]
                    if missing:
                        return build_error_response(
                            400,
                            f"Missing required fields: {', '.join(missing)}",
                            request_id
                        )
                
                logger.info(
                    f"Processing request: function={function_name}, "
                    f"request_id={request_id}"
                )
                
                # Execute the handler
                result = func(event, context)
                
                # Warn if execution is taking too long
                elapsed = time.time() - start_time
                remaining_ms = getattr(context, 'get_remaining_time_in_millis', lambda: 30000)()
                
                if elapsed > max_execution_time_warning:
                    logger.warning(
                        f"Slow execution: {elapsed:.2f}s, "
                        f"remaining: {remaining_ms}ms"
                    )
                
                logger.info(
                    f"Request completed: request_id={request_id}, "
                    f"elapsed={elapsed:.2f}s"
                )
                
                return result
                
            except InputValidationError as e:
                logger.warning(f"Input validation failed: {e}, request_id={request_id}")
                return build_error_response(400, str(e), request_id)
            
            except SecurityViolationError as e:
                logger.error(f"SECURITY VIOLATION: {e}, request_id={request_id}")
                # Don't reveal security details to caller
                return build_error_response(403, "Access denied", request_id)
            
            except ClientError as e:
                error_code = e.response['Error']['Code']
                logger.error(
                    f"AWS ClientError: {error_code}, request_id={request_id}",
                    exc_info=True
                )
                # Don't leak AWS error details
                if error_code in ('AccessDeniedException', 'UnauthorizedAccess'):
                    return build_error_response(403, "Access denied", request_id)
                elif error_code == 'ResourceNotFoundException':
                    return build_error_response(404, "Resource not found", request_id)
                elif error_code == 'ConditionalCheckFailedException':
                    return build_error_response(409, "Conflict", request_id)
                elif error_code == 'ProvisionedThroughputExceededException':
                    return build_error_response(429, "Too many requests", request_id)
                else:
                    return build_error_response(500, "Internal server error", request_id)
            
            except Exception as e:
                logger.error(
                    f"Unhandled exception: request_id={request_id}",
                    exc_info=True
                )
                # Never expose internal error details
                return build_error_response(500, "Internal server error", request_id)
        
        return wrapper
    return decorator


def build_error_response(status_code: int, message: str, request_id: str) -> dict:
    """Build a standardized error response."""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Request-Id': request_id,
            # Security headers
            'X-Content-Type-Options': 'nosniff',
            'Cache-Control': 'no-store',
            'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        },
        'body': json.dumps({
            'error': message,
            'requestId': request_id
        })
    }


def build_success_response(body: Any, request_id: str,
                            status_code: int = 200) -> dict:
    """Build a standardized success response."""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Request-Id': request_id,
            # Security headers
            'X-Content-Type-Options': 'nosniff',
            'Cache-Control': 'no-store',
            'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        },
        'body': json.dumps(body, default=str)
    }


# =========================================================
# EXAMPLE LAMBDA HANDLER
# This demonstrates how any of the 10+ Lambda functions
# would use the shared role and secure client pattern.
# =========================================================

# Table and resource names derived from environment
ORDERS_TABLE = f"{SERVICE_PREFIX}-{ENVIRONMENT}-orders"
NOTIFICATIONS_TOPIC = f"{SERVICE_PREFIX}-{ENVIRONMENT}-notifications"
PROCESSING_QUEUE = f"{SERVICE_PREFIX}-{ENVIRONMENT}-processing"
DATA_BUCKET = f"{SERVICE_PREFIX}-{ENVIRONMENT}-data"


@secure_handler(require_fields=['action'])
def lambda_handler(event, context):
    """
    Example microservice handler that demonstrates secure usage
    of S3, DynamoDB, SNS, and SQS through the shared IAM role.
    
    All 10+ Lambda functions follow this same pattern:
    1. Use @secure_handler for input validation and error handling
    2. Use SecureServiceClients for AWS access with resource scoping
    3. Reference the shared IAM role ARN from CloudFormation exports
    
    SAM/CloudFormation reference for this function:
    
      MyFunction:
        Type: AWS::Serverless::Function
        Properties:
          FunctionName: !Sub '${ServicePrefix}-${Environment}-order-processor'
          Role: !ImportValue
            Fn::Sub: '${ServicePrefix}-${Environment}-shared-lambda-role-arn'
          PermissionsBoundary: !ImportValue
            Fn::Sub: '${ServicePrefix}-${Environment}-lambda-boundary-arn'
          Environment:
            Variables:
              ENVIRONMENT: !Ref Environment
              SERVICE_PREFIX: !Ref ServicePrefix
              LOG_LEVEL: INFO
    """
    request_id = context.aws_request_id
    clients = SecureServiceClients.get_instance()
    
    action = sanitize_string(event['action'], max_length=50, field_name="action")
    
    if action == 'create_order':
        return _handle_create_order(event, clients, request_id)
    elif action == 'get_order':
        return _handle_get_order(event, clients, request_id)
    elif action == 'process_order':
        return _handle_process_order(event, clients, request_id)
    elif action == 'export_order':
        return _handle_export_order(event, clients, request_id)
    else:
        return build_error_response(400, f"Unknown action: {action}", request_id)


def _handle_create_order(event: dict, clients: SecureServiceClients,
                          request_id: str) -> dict:
    """Create a new order in DynamoDB and notify via SNS."""
    # Validate required fields
    required = ['order_id', 'customer_id', 'items']
    missing = [f for f in required if f not in event]
    if missing:
        return build_error_response(
            400, f"Missing fields: {', '.join(missing)}", request_id
        )
    
    order_id = sanitize_string(event['order_id'], max_length=64, field_name="order_id")
    customer_id = sanitize_string(event['customer_id'], max_length=64, field_name="customer_id")
    
    if not re.match(r'^[a-zA-Z0-9\-_]+$', order_id):
        return build_error_response(400, "Invalid order_id format", request_id)
    if not re.match(r'^[a-zA-Z0-9\-_]+$', customer_id):
        return build_error_response(400, "Invalid customer_id format", request_id)
    
    items = event['items']
    if not isinstance(items, list) or len(items) == 0 or len(items) > 100:
        return build_error_response(400, "Items must be a list with 1-100 entries", request_id)
    
    # Store in DynamoDB
    order_item = {
        'order_id': order_id,
        'customer_id': customer_id,
        'items': items,
        'status': 'created',
        'created_at': int(time.time()),
        'request_id': request_id
    }
    
    clients.dynamodb_put_item(ORDERS_TABLE, order_item)
    
    # Send notification via SNS
    notification = json.dumps({
        'event_type': 'order_created',
        'order_id': order_id,
        'customer_id': customer_id,
        'timestamp': int(time.time())
    })
    
    clients.sns_publish(
        NOTIFICATIONS_TOPIC,
        notification,
        subject='Order Created'
    )
    
    # Queue for processing via SQS
    clients.sqs_send_message(
        PROCESSING_QUEUE,
        json.dumps({'order_id': order_id, 'action': 'process'}),
        delay_seconds=5
    )
    
    return build_success_response(
        {'order_id': order_id, 'status': 'created'},
        request_id,
        status_code=201
    )


def _handle_get_order(event: dict, clients: SecureServiceClients,
                       request_id: str) -> dict:
    """Retrieve an order from DynamoDB."""
    if 'order_id' not in event:
        return build_error_response(400, "Missing order_id", request_id)
    
    order_id = sanitize_string(event['order_id'], max_length=64, field_name="order_id")
    
    if not re.match(r'^[a-zA-Z0-9\-_]+$', order_id):
        return build_error_response(400, "Invalid order_id format", request_id)
    
    item = clients.dynamodb_get_item(ORDERS_TABLE, {'order_id': order_id})
    
    if not item:
        return build_error_response(404, "Order not found", request_id)
    
    return build_success_response(item, request_id)


def _handle_process_order(event: dict, clients: SecureServiceClients,
                           request_id: str) -> dict:
    """Process an order: update status and notify."""
    if 'order_id' not in event:
        return build_error_response(400, "Missing order_id", request_id)
    
    order_id = sanitize_string(event['order_id'], max_length=64, field_name="order_id")
    
    if not re.match(r'^[a-zA-Z0-9\-_]+$', order_id):
        return build_error_response(400, "Invalid order_id format", request_id)
    
    # Update order status in DynamoDB
    result = clients.dynamodb_update_item(
        ORDERS_TABLE,
        key={'order_id': order_id},
        update_expression='SET #status = :status, #updated = :updated, #rid = :rid',
        expression_values={
            ':status': 'processing',
            ':updated': int(time.time()),
            ':rid': request_id
        },
        expression_names={
            '#status': 'status',
            '#updated': 'updated_at',
            '#rid': 'last_request_id'
        }
    )
    
    # Notify about status change
    clients.sns_publish(
        NOTIFICATIONS_TOPIC,
        json.dumps({
            'event_type': 'order_processing',
            'order_id': order_id,
            'timestamp': int(time.time())
        }),
        subject='Order Processing'
    )
    
    return build_success_response(
        {'order_id': order_id, 'status': 'processing'},
        request_id
    )


def _handle_export_order(event: dict, clients: SecureServiceClients,
                          request_id: str) -> dict:
    """Export an order to S3 as JSON."""
    if 'order_id' not in event:
        return build_error_response(400, "Missing order_id", request_id)
    
    order_id = sanitize_string(event['order_id'], max_length=64, field_name="order_id")
    
    if not re.match(r'^[a-zA-Z0-9\-_]+$', order_id):
        return build_error_response(400, "Invalid order_id format", request_id)
    
    # Get order from DynamoDB
    item = clients.dynamodb_get_item(ORDERS_TABLE, {'order_id': order_id})
    
    if not item:
        return build_error_response(404, "Order not found", request_id)
    
    # Export to S3 with encryption
    export_data = json.dumps(item, default=str).encode('utf-8')
    s3_key = f"exports/orders/{order_id}/{int(time.time())}.json"
    
    clients.s3_put_object(
        DATA_BUCKET,
        s3_key,
        export_data,
        server_side_encryption='AES256',
        content_type='application/json'
    )
    
    return build_success_response(
        {
            'order_id': order_id,
            'export_bucket': DATA_BUCKET,
            'export_key': s3_key
        },
        request_id
    )


# =========================================================
# SECURITY NOTES FOR THE SHARED ROLE APPROACH
# =========================================================
#
# TRADE-OFFS OF A SHARED IAM ROLE:
#
# Pros:
#   - Reduces IAM role sprawl (1 role vs 10+ roles)
#   - Simpler deployment and management
#   - Consistent permissions across services
#   - Easier auditing of a single role
#
# Cons:
#   - Violates least privilege (each function gets all permissions)
#   - Blast radius: if one function is compromised, attacker has
#     access to all resources the shared role can reach
#   - Harder to track which function accessed which resource
#
# MITIGATIONS IMPLEMENTED:
#
# 1. RESOURCE-LEVEL RESTRICTIONS: All IAM policies scope access to
#    resources with the service prefix (e.g., myapp-prod-*)
#
# 2. PERMISSIONS BOUNDARY: Prevents privilege escalation even if
#    the role is somehow modified
#
# 3. EXPLICIT DENY STATEMENTS: Critical destructive actions
#    (DeleteTable, DeleteTopic, etc.) are explicitly denied
#
# 4. APPLICATION-LEVEL ENFORCEMENT: SecureServiceClients validates
#    all resource names against allowed prefixes before making
#    AWS API calls (defense in depth)
#
# 5. INPUT VALIDATION: All inputs are sanitized and validated
#    before use
#
# 6. LOG SANITIZATION: Prevents log injection attacks
#
# 7. ERROR HANDLING: Internal errors are never exposed to callers
#
# RECOMMENDED EVOLUTION:
#   As the architecture matures, consider splitting into
#   role-per-function or role-per-service-group for better
#   isolation. Use AWS Organizations SCPs for additional guardrails.
# =========================================================